import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";
import Modal from "../components/Modal";

function Schedules() {
  const [schedules, setSchedules] = useState([]);
  const [courses, setCourses] = useState([]);
  const [classes, setClasses] = useState([]);
  const [newSchedule, setNewSchedule] = useState({ classId: "", courseId: "", date: "", time: "" });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [scheduleToDelete, setScheduleToDelete] = useState(null);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch("http://localhost:3001/schedules")
      .then((res) => res.json())
      .then((data) => setSchedules(data));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data));
  }, []);

  async function handleAddSchedule(e) {
    e.preventDefault();
    try {
      const response = await fetch("http://localhost:3001/schedules", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          classId: parseInt(newSchedule.classId),
          courseId: parseInt(newSchedule.courseId),
          date: newSchedule.date,
          time: newSchedule.time,
        }),
      });
      if (response.ok) {
        const schedule = await response.json();
        setSchedules([...schedules, schedule]);
        setNewSchedule({ classId: "", courseId: "", date: "", time: "" });
        toast.success("Расписание добавлено!");
      } else {
        toast.error("Не удалось добавить расписание");
      }
    } catch (error) {
      toast.error("Сетевая ошибка");
    }
  }

  async function handleDeleteSchedule() {
    try {
      const response = await fetch(`http://localhost:3001/schedules/${scheduleToDelete}`, {
        method: "DELETE",
      });
      if (response.ok) {
        setSchedules(schedules.filter((s) => s.id !== scheduleToDelete));
        toast.success("Расписание удалено!");
      } else {
        toast.error("Не удалось удалить расписание");
      }
    } catch (error) {
      toast.error("Сетевая ошибка");
    }
    setIsModalOpen(false);
  }

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Управление расписанием</h1>
      <div className="card mb-4">
        <div className="card-body">
          <h3>Добавить расписание</h3>
          <form onSubmit={handleAddSchedule}>
            <div className="row">
              <div className="col-md-3 mb-3">
                <select
                  className="form-select"
                  value={newSchedule.classId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, classId: e.target.value })}
                  required
                >
                  <option value="">Класс</option>
                  {classes.map((cls) => (
                    <option key={cls.id} value={cls.id}>{cls.name}</option>
                  ))}
                </select>
              </div>
              <div className="col-md-3 mb-3">
                <select
                  className="form-select"
                  value={newSchedule.courseId}
                  onChange={(e) => setNewSchedule({ ...newSchedule, courseId: e.target.value })}
                  required
                >
                  <option value="">Курс</option>
                  {courses.map((course) => (
                    <option key={course.id} value={course.id}>{course.name}</option>
                  ))}
                </select>
              </div>
              <div className="col-md-3 mb-3">
                <input
                  type="date"
                  className="form-control"
                  value={newSchedule.date}
                  onChange={(e) => setNewSchedule({ ...newSchedule, date: e.target.value })}
                  required
                />
              </div>
              <div className="col-md-3 mb-3">
                <input
                  type="time"
                  className="form-control"
                  value={newSchedule.time}
                  onChange={(e) => setNewSchedule({ ...newSchedule, time: e.target.value })}
                  required
                />
              </div>
            </div>
            <button type="submit" className="btn btn-primary w-100">Добавить</button>
          </form>
        </div>
      </div>
      <ul className="list-group">
        {schedules.map((schedule) => {
          const course = courses.find((c) => c.id === schedule.courseId);
          const cls = classes.find((c) => c.id === schedule.classId);
          return (
            <li key={schedule.id} className="list-group-item d-flex justify-content-between align-items-center">
              <span>
                Класс: {cls?.name} | Курс: {course?.name} | Дата: {schedule.date} | Время: {schedule.time}
              </span>
              <button
                onClick={() => {
                  setScheduleToDelete(schedule.id);
                  setIsModalOpen(true);
                }}
                className="btn btn-danger btn-sm"
              >
                Удалить
              </button>
            </li>
          );
        })}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleDeleteSchedule}
        message="Вы уверены, что хотите удалить это расписание?"
      />
    </div>
  );
}

export default Schedules;
